#include <vector>
#include <unordered_map>
#include <algorithm>

long long solve(std::vector<long long> nums, long long k) {
    std::unordered_map<long long, long long> prefix_mod;
    prefix_mod[0] = 0;
    long long total = 0;
    long long min_sum = std::numeric_limits<long long>::max();

    for (long long num : nums) {
        total += num;
        long long mod = total % k;
        if (mod == 0) {
            min_sum = std::min(min_sum, total);
        } else {
            // Check if there is a previous prefix with the same mod
            // If so, the subarray between those indices has sum divisible by k
            if (prefix_mod.find(mod) != prefix_mod.end()) {
                min_sum = std::min(min_sum, total - prefix_mod[mod]);
            } else {
                prefix_mod[mod] = total;
            }
        }
    }

    return min_sum;
}

